CREATE TABLE IF NOT EXISTS USERS(ID INTEGER PRIMARY KEY AUTOINCREMENT,FIRSTNAME VARCHAR(50),LASTNAME VARCHAR(50),EMAIL VARCHAR(50), account_password VARCHAR(50) , user_id VARCHAR(50));
CREATE TABLE IF NOT EXISTS PROJECTS(PROJECT_ID INTEGER PRIMARY KEY AUTOINCREMENT,PROJECT_NAME VARCHAR(50),PROJECT_START_DATE TEXT DEFAULT CURRENT_TIMESTAMP,PROJECT_END_DATE TEXT, STATUS TEXT DEFAULT 'NOT_STARTED',PLANNED_EFFORTS INTEGER,SPENDED_EFFORTS INTEGER);
CREATE TABLE IF NOT EXISTS SUBTASKS(PROJECT_ID INTEGER PRIMARY KEY, SUBTASK_NAME TEXT, STATUS TEXT DEFAULT 'NOT_STARTED',EXPECTED_EFFORTS INT, SPENDED_EFFORTS INT, START_DATE TEXT, END_DATE TEXT);
